import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  ToggleButton,
  ToggleButtonGroup,
  Paper,
  Alert,
  CircularProgress,
} from "@mui/material";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Signup() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    mobile: "",
    role: "user",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleRoleChange = (event, newRole) => {
    if (newRole) setFormData({ ...formData, role: newRole.toLowerCase() });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      const response = await axios.post(
        "http://localhost:5000/api/auth/signup",
        formData
      );

      if (response.data.success) {
        navigate("/login"); // Redirect after successful signup
      } else {
        setError(response.data.message || "Signup failed.");
      }
    } catch (err) {
      if (err.response) {
        setError(err.response.data.message || "Server responded with an error.");
      } else if (err.request) {
        setError("No response from server. Make sure backend is running.");
      } else {
        setError("Something went wrong: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ padding: 4, marginTop: 5 }}>
        <Typography variant="h4" color="orange" align="center" gutterBottom>
          Rider App
        </Typography>
        <Typography variant="body1" align="center" gutterBottom>
          Create your account to get started
        </Typography>

        {error && <Alert severity="error">{error}</Alert>}

        <Box component="form" onSubmit={handleSubmit} sx={{ mt: 2 }}>
          <TextField
            fullWidth
            label="Full Name"
            name="fullName"
            value={formData.fullName}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Email"
            name="email"
            type="email"
            value={formData.email}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Mobile Number"
            name="mobile"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            required
          />

          <Typography variant="subtitle1" sx={{ mt: 2 }}>
            Role
          </Typography>
          <ToggleButtonGroup
            value={formData.role}
            exclusive
            onChange={handleRoleChange}
            fullWidth
            sx={{ mb: 2 }}
          >
            <ToggleButton value="user">USER</ToggleButton>
            <ToggleButton value="owner">OWNER</ToggleButton>
          </ToggleButtonGroup>

          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ bgcolor: "orange", "&:hover": { bgcolor: "#ff6600" } }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} color="inherit" /> : "REGISTER"}
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}
